mapper.select:
SELECT sl.id, sl.category_id_list, sl.email, sl.is_success, sl.delivery_date, sd.create_date, sd.title AS news_title, sd.content AS news_content FROM send_log sl LEFT JOIN user u ON sl.user_id = u.id LEFT JOIN summary_data sd ON DATE(sl.delivery_date) = DATE(sd.create_date) AND sl.category_id_list LIKE CONCAT('%', sd.category_id, '%')
u.id = #{userId}
AND sl.is_success = #{isSuccess}
ORDER BY alarm_time DESC LIMIT #{size} OFFSET #{offset}
